<?php/* Config Section */$pass		= ' ';				// Set the password.$cookiename	= 'urlcookie';				// Optional change: Give the cookie a name. Default is sascookie$expirytime	= time()+3600;				// Optional change: Set an expiry time for the password (in seconds). Default is 1 hour.$msg		= 'This password is incorrect. (6 characters minimum)';	// Optional change: Error message displayed when password is incorrect. Default is "Password incorrect"./* End Config *//* Logout Stuff - Sept 5, 2005 */if (isset($_REQUEST['logout'])) {	setcookie($cookiename,'',time() - 3600);							// remove cookie/password	if (substr($_SERVER['REQUEST_URI'],-12)=='?logout=true') {			// if there is '?logout=true' in the URL		$url=str_replace('?logout=true','',$_SERVER['REQUEST_URI']);	// remove the string '?logout=true' from the URL		header('Location: '.$url);										// redirect the browser to original URL	}	show_login_page('');	exit();}$logout_button='<form action="'.$_SERVER['REQUEST_URI'].'" method="post"><input type="submit" name="logout" value="Logout" /></form>';$logout_text='<a href="'.$_SERVER['REQUEST_URI'].'?logout=true">Logout</a>';/* End Logout Stuff *//* FUNCTIONS */function setmycookie() {global $cookiename,$pass,$expirytime;	setcookie($cookiename,$pass,$expirytime);}	function show_login_page($msg) {?><!DOCTYPE html PUBLIC "-//W3C//DTD XHTML 1.0 Transitional//EN" "http://www.w3.org/TR/xhtml1/DTD/xhtml1-transitional.dtd"><html xmlns="http://www.w3.org/1999/xhtml"><head><title>Authorization Required</title><style type="text/css"><!--.error {color:#A80000}#main {text-align:center;padding:15px}#header {font:bold 130% Verdana, Arial, sans-serif;color:#DDDDDD;width:100%;height:3em;text-align:center;background:#000000;line-height:3em}#mid {margin:3em 0 3em 0}#footer {font-size:75%;text-align:center;width:100%}--></style> <script language="JavaScript" type="text/javascript">  <!--  function focus() {  	document.pass.password.select();  	document.pass.password.focus();  }  //-->  </script> </HEAD> <BODY onLoad="focus()">	<div id="header">Sorry, authorization please</div><div id="main">	<div id="mid">		<form action="" name="pass" method="POST">        Your password is:&nbsp;         <input type="password" name="password" size="20">&nbsp;			<input type="submit" value="Login">			<input type="hidden" name="sub" value="sub">		</form>		<div class=error><?=$msg?></div>	</div></div></body></html><? }/* END FUNCTIONS */$errormsg='';if (isset($_POST['sub'])) {						// if form has been submitted	if ($_POST['password']<>$pass) {			// if password is incorrect		$errormsg=$msg;		show_login_page($errormsg);		exit();	} else {									// if password is correct		setmycookie();	}} else {	if (isset($_COOKIE[$cookiename])) {			// if cookie isset        if ($_COOKIE[$cookiename]==$pass) {		// if cookie is correct		   // do nothing		} else {								// if cookie is incorrect			show_login_page($errormsg);			exit();		}	} else {									// if cookie is not set		show_login_page($errormsg);		exit();	}}?>